import React from "react";
import styleLogo from "./Logo.module.css";

const Logo = () => {
  return (
    <div className={styleLogo.container}>
      <svg x="0px" y="0px" viewBox="0 0 174.4 174.4">
        <g>
          <path
            className={styleLogo.path}
            d="M158.6,0H15.8C7.1,0,0,7.1,0,15.8v142.8c0,8.7,7.1,15.8,15.8,15.8h142.8c8.7,0,15.8-7.1,15.8-15.8V15.8
		C174.4,7.1,167.3,0,158.6,0z M163.4,158.6c0,2.7-2.2,4.8-4.8,4.8H15.8c-2.7,0-4.8-2.2-4.8-4.8V15.8c0-2.7,2.2-4.8,4.8-4.8h142.8
		c2.7,0,4.8,2.2,4.8,4.8V158.6z"
          />
          <rect
            className={styleLogo.path}
            x="78.8"
            y="60.2"
            class="st0"
            width="16.8"
            height="90.7"
          />
          <circle className={styleLogo.path} cx="87.2" cy="38.5" r="15" />
        </g>
      </svg>
    </div>
  );
};

export default Logo;
